using Autodesk.AutoCAD.DatabaseServices;using Autodesk.AutoCAD.Geometry;using System;using System.Collections.Generic;using System.Linq;
namespace Tgirrr.CadLisp { internal static class DripLayoutService {internal static Vector2d Direction(Polyline p){double best=-1;Vector2d dir=Vector2d.XAxis;for(int i=0;i<p.NumberOfVertices;i++){if(p.GetSegmentType(i)!=SegmentType.Line)continue;var seg=p.GetLineSegment2dAt(i);if(seg.Length>best){best=seg.Length;dir=seg.Direction;}}return dir.GetNormal();}internal static DBObjectCollection Inner(Polyline p,double inset){if(inset==0){var c=new DBObjectCollection();c.Add(p.Clone() as Polyline);return c;}DBObjectCollection a=null,b=null;try{a=p.GetOffsetCurves(inset);}catch{}try{b=p.GetOffsetCurves(-inset);}catch{}var candidates=new List<Polyline>();if(a!=null)candidates.AddRange(a.Cast<DBObject>().OfType<Polyline>());if(b!=null)candidates.AddRange(b.Cast<DBObject>().OfType<Polyline>());var inside=candidates.Where(x=>PointInside(p,x.GetPoint2dAt(0))).OrderByDescending(x=>Math.Abs(x.Area)).ToList();var result=new DBObjectCollection();foreach(var x in inside)result.Add(x);foreach(var x in candidates.Except(inside))x.Dispose();return result;}internal static bool PointInside(Polyline p,Point2d point){var far=new LineSegment2d(point,new Point2d(p.GeometricExtents.MaxPoint.X+(p.GeometricExtents.MaxPoint-p.GeometricExtents.MinPoint).Length+1,point.Y+0.1234567));int hits=0;for(int i=0;i<p.NumberOfVertices;i++){if(p.GetSegmentType(i)==SegmentType.Line){var pts=p.GetLineSegment2dAt(i).IntersectWith(far);hits+=pts?.Length??0;}else if(p.GetSegmentType(i)==SegmentType.Arc){var pts=p.GetArcSegment2dAt(i).IntersectWith(far);hits+=pts?.Length??0;}}return hits%2==1;}internal static List<Line> Fill(Polyline boundary,double spacing,Vector2d direction){var normal=direction.GetPerpendicularVector();var ext=boundary.GeometricExtents;var corners=new[]{new Point2d(ext.MinPoint.X,ext.MinPoint.Y),new Point2d(ext.MinPoint.X,ext.MaxPoint.Y),new Point2d(ext.MaxPoint.X,ext.MinPoint.Y),new Point2d(ext.MaxPoint.X,ext.MaxPoint.Y)};double min=corners.Min(p=>p.GetAsVector().DotProduct(normal)),max=corners.Max(p=>p.GetAsVector().DotProduct(normal)),reach=(ext.MaxPoint-ext.MinPoint).Length*2+spacing;var result=new List<Line>();for(double d=Math.Ceiling(min/spacing)*spacing;d<=max;d+=spacing){var center=new Point2d(normal.X*d,normal.Y*d);var a=center-direction*reach;var b=center+direction*reach;var probe=new Line(new Point3d(a.X,a.Y,0),new Point3d(b.X,b.Y,0));var points=new Point3dCollection();boundary.IntersectWith(probe,Intersect.OnBothOperands,points,IntPtr.Zero,IntPtr.Zero);probe.Dispose();var ordered=points.Cast<Point3d>().OrderBy(p=>p.GetAsVector().DotProduct(new Vector3d(direction.X,direction.Y,0))).ToList();for(int i=0;i+1<ordered.Count;i++){var mid=new Point2d((ordered[i].X+ordered[i+1].X)/2,(ordered[i].Y+ordered[i+1].Y)/2);if(PointInside(boundary,mid))result.Add(new Line(ordered[i],ordered[i+1]));}}return result;}}
}
